:root {
  --navy: #0b1f33;
  --green: #18a957;
  --muted: #667487;
  --border: #dbe4ed;
  --surface: #ffffff;
  --bg: #f5f8fb;
  --danger: #8a4a00;
}

* {
  box-sizing: border-box;
}

body {
  margin: 0;
  color: #142234;
  background: var(--bg);
  font-family: Inter, system-ui, -apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif;
}

a {
  color: inherit;
}

input,
textarea,
select,
button {
  font: inherit;
}

button {
  border: 0;
  border-radius: 8px;
  padding: 10px 14px;
  color: #fff;
  background: var(--green);
  cursor: pointer;
  font-weight: 700;
}

input,
textarea,
select {
  width: 100%;
  border: 1px solid var(--border);
  border-radius: 8px;
  padding: 10px 11px;
  background: #fff;
}

label {
  display: grid;
  gap: 6px;
  color: var(--muted);
  font-size: 0.9rem;
  font-weight: 700;
}

code {
  padding: 2px 5px;
  border-radius: 6px;
  background: #eef3f8;
}

.admin-login {
  display: grid;
  min-height: 100vh;
  place-items: center;
}

.login-card {
  width: min(420px, calc(100% - 32px));
  padding: 30px;
  border: 1px solid var(--border);
  border-radius: 8px;
  background: var(--surface);
  box-shadow: 0 18px 45px rgba(11, 31, 51, 0.12);
}

.login-card h1 {
  margin: 0;
}

.login-card p {
  color: var(--muted);
}

.login-card form {
  display: grid;
  gap: 14px;
}

.admin-header {
  position: sticky;
  top: 0;
  z-index: 10;
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 16px clamp(16px, 4vw, 46px);
  color: #fff;
  background: var(--navy);
}

.admin-header span {
  display: block;
  color: rgba(255, 255, 255, 0.7);
  font-size: 0.86rem;
}

.admin-header nav {
  display: flex;
  gap: 14px;
}

.admin-shell {
  display: grid;
  gap: 18px;
  width: min(1180px, calc(100% - 32px));
  margin: 26px auto 60px;
}

.panel,
.notice,
.alert {
  border: 1px solid var(--border);
  border-radius: 8px;
  background: #fff;
}

.panel {
  padding: 22px;
}

.panel h2 {
  margin: 0 0 16px;
  color: var(--navy);
}

.warning {
  border-color: rgba(242, 186, 54, 0.5);
  background: #fff8e5;
}

.warning li {
  margin: 5px 0;
}

.notice,
.alert {
  padding: 12px 14px;
}

.alert {
  color: #8f1d1d;
  background: #fff0f0;
}

.grid-form {
  display: grid;
  grid-template-columns: repeat(2, minmax(0, 1fr));
  gap: 14px;
}

.grid-form .wide {
  grid-column: 1 / -1;
}

.grid-form .checkbox {
  display: flex;
  align-items: center;
  gap: 8px;
}

.grid-form .checkbox input {
  width: auto;
}

.table-wrap {
  overflow-x: auto;
}

table {
  width: 100%;
  border-collapse: collapse;
}

th,
td {
  padding: 10px;
  border-bottom: 1px solid var(--border);
  text-align: left;
  vertical-align: top;
}

th {
  color: var(--muted);
  font-size: 0.82rem;
}

.inline-form {
  display: grid;
  grid-template-columns: minmax(130px, 1fr) auto;
  gap: 8px;
}

@media (max-width: 760px) {
  .admin-header,
  .grid-form {
    grid-template-columns: 1fr;
  }

  .grid-form {
    display: grid;
  }
}

:root {
  color-scheme: light;
  --tp-navy: #0b1f33;
  --tp-navy-2: #123653;
  --tp-green: #18a957;
  --tp-green-dark: #0d7d42;
  --tp-green-soft: #e6f7ed;
  --tp-blue: #1b6fd8;
  --tp-yellow: #f2ba36;
  --tp-ink: #142234;
  --tp-muted: #5b6a7d;
  --tp-border: #dbe4ed;
  --tp-surface: #ffffff;
  --tp-surface-alt: #f5f8fb;
  --tp-shadow: 0 18px 45px rgba(11, 31, 51, 0.12);
  --md-ref-typeface-brand: 'Inter', system-ui, sans-serif;
  --md-ref-typeface-plain: 'Inter', system-ui, sans-serif;
  --md-sys-color-primary: var(--tp-green);
  --md-sys-color-on-primary: #ffffff;
  --md-sys-color-secondary: var(--tp-navy);
  --md-sys-color-surface: #ffffff;
  --md-sys-color-on-surface: var(--tp-ink);
  --md-sys-shape-corner-full: 8px;
}

* {
  box-sizing: border-box;
}

html {
  scroll-behavior: smooth;
}

body {
  margin: 0;
  color: var(--tp-ink);
  background: var(--tp-surface);
  font-family: 'Inter', system-ui, -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif;
  line-height: 1.55;
}

a {
  color: inherit;
  text-decoration: none;
}

img {
  display: block;
  max-width: 100%;
}

button,
select,
input,
textarea {
  font: inherit;
}

.sr-only {
  position: absolute;
  width: 1px;
  height: 1px;
  padding: 0;
  margin: -1px;
  overflow: hidden;
  clip: rect(0, 0, 0, 0);
  white-space: nowrap;
  border: 0;
}

.site-header {
  position: sticky;
  top: 0;
  z-index: 20;
  display: grid;
  grid-template-columns: auto 1fr auto;
  align-items: center;
  gap: 24px;
  padding: 14px clamp(18px, 4vw, 56px);
  background: rgba(255, 255, 255, 0.94);
  border-bottom: 1px solid rgba(219, 228, 237, 0.9);
  backdrop-filter: blur(14px);
}

.brand {
  display: inline-flex;
  align-items: center;
  gap: 10px;
}

.brand-mark {
  display: grid;
  place-items: center;
  width: 38px;
  height: 38px;
  border-radius: 8px;
  background: linear-gradient(135deg, var(--tp-navy), var(--tp-green));
  color: #fff;
  font-weight: 800;
  letter-spacing: 0;
}

.brand strong,
.brand small {
  display: block;
  line-height: 1.05;
}

.brand small {
  color: var(--tp-muted);
  font-size: 0.76rem;
  font-weight: 600;
}

.site-nav {
  display: flex;
  justify-content: center;
  gap: clamp(12px, 2vw, 28px);
  color: var(--tp-muted);
  font-size: 0.92rem;
  font-weight: 650;
}

.site-nav a {
  padding: 8px 0;
}

.site-nav a:hover {
  color: var(--tp-green-dark);
}

.header-actions {
  display: flex;
  align-items: center;
  gap: 12px;
}

.language-control select,
.field-label select {
  min-height: 42px;
  border: 1px solid var(--tp-border);
  border-radius: 8px;
  padding: 0 36px 0 12px;
  color: var(--tp-ink);
  background: #fff;
  font-weight: 650;
}

.section-shell {
  width: min(1180px, calc(100% - 36px));
  margin: 0 auto;
  padding: 86px 0;
}

.hero {
  display: grid;
  grid-template-columns: minmax(440px, 1fr) minmax(430px, 1.02fr);
  gap: 48px;
  align-items: center;
  min-height: calc(100vh - 72px);
  padding-top: 58px;
  padding-bottom: 54px;
}

.hero h1 {
  margin: 0;
  max-width: 760px;
  font-size: clamp(2.6rem, 4vw, 4.8rem);
  line-height: 1.02;
  letter-spacing: 0;
  color: var(--tp-navy);
}

.hero p {
  max-width: 680px;
  margin: 24px 0 0;
  color: var(--tp-muted);
  font-size: clamp(1rem, 1.4vw, 1.2rem);
}

.hero-actions {
  display: flex;
  flex-wrap: wrap;
  gap: 12px;
  margin-top: 34px;
}

.hero-visual {
  position: relative;
  overflow: hidden;
  border-radius: 8px;
  background: var(--tp-navy);
  box-shadow: var(--tp-shadow);
  aspect-ratio: 16 / 11;
}

.hero-visual img {
  width: 100%;
  height: 100%;
  object-fit: cover;
}

.proof-strip {
  display: grid;
  grid-template-columns: repeat(3, minmax(0, 1fr));
  gap: 12px;
  margin-top: 36px;
  max-width: 680px;
}

.proof-strip span {
  padding: 16px 14px;
  border-left: 3px solid var(--tp-green);
  background: var(--tp-surface-alt);
}

.proof-strip b,
.proof-strip small {
  display: block;
}

.proof-strip b {
  color: var(--tp-navy);
  font-size: 1.45rem;
  line-height: 1.1;
}

.proof-strip small {
  color: var(--tp-muted);
  font-size: 0.78rem;
  font-weight: 650;
}

.section-heading {
  max-width: 760px;
  margin: 0 auto 36px;
  text-align: center;
}

.section-heading.align-left {
  margin-left: 0;
  text-align: left;
}

.section-heading h2,
.operational-copy h2 {
  margin: 0;
  color: var(--tp-navy);
  font-size: clamp(2rem, 3.2vw, 3.25rem);
  line-height: 1.05;
  letter-spacing: 0;
}

.section-heading p,
.operational-copy p {
  margin: 14px 0 0;
  color: var(--tp-muted);
  font-size: 1.03rem;
}

.coverage-section,
.setup-section {
  border-top: 1px solid var(--tp-border);
}

.coverage-grid {
  display: grid;
  grid-template-columns: minmax(0, 1.05fr) minmax(360px, 0.95fr);
  gap: 28px;
  align-items: stretch;
}

.coverage-map,
.map-panel {
  min-height: 430px;
}

.coverage-map {
  padding: 16px;
  background: var(--tp-navy);
  border-radius: 8px;
  box-shadow: var(--tp-shadow);
}

.map-panel {
  position: relative;
  overflow: hidden;
  border: 1px solid rgba(255, 255, 255, 0.16);
  border-radius: 8px;
  background:
    linear-gradient(rgba(255, 255, 255, 0.05) 1px, transparent 1px),
    linear-gradient(90deg, rgba(255, 255, 255, 0.05) 1px, transparent 1px),
    radial-gradient(circle at 32% 38%, rgba(24, 169, 87, 0.22), transparent 26%),
    radial-gradient(circle at 76% 64%, rgba(27, 111, 216, 0.18), transparent 26%),
    var(--tp-navy);
  background-size: 42px 42px, 42px 42px, auto, auto, auto;
}

.map-panel::before {
  content: "";
  position: absolute;
  inset: 54px 48px;
  border: 1px solid rgba(255, 255, 255, 0.24);
  clip-path: polygon(34% 9%, 61% 7%, 78% 22%, 84% 45%, 74% 67%, 52% 79%, 29% 72%, 17% 52%, 19% 25%);
}

.node {
  position: absolute;
  z-index: 2;
  width: 13px;
  height: 13px;
  border-radius: 50%;
  background: var(--tp-green);
  box-shadow: 0 0 0 8px rgba(24, 169, 87, 0.18), 0 0 22px rgba(24, 169, 87, 0.85);
}

.n1 { left: 27%; top: 24%; }
.n2 { left: 53%; top: 21%; }
.n3 { left: 69%; top: 35%; }
.n4 { left: 58%; top: 53%; }
.n5 { left: 43%; top: 61%; }
.n6 { left: 29%; top: 54%; }
.n7 { left: 76%; top: 66%; }
.n8 { left: 61%; top: 75%; }
.n9 { left: 38%; top: 39%; }

.map-line {
  position: absolute;
  height: 1px;
  background: linear-gradient(90deg, transparent, rgba(24, 169, 87, 0.8), transparent);
  transform-origin: left center;
}

.l1 { left: 29%; top: 26%; width: 42%; transform: rotate(11deg); }
.l2 { left: 32%; top: 55%; width: 45%; transform: rotate(-12deg); }
.l3 { left: 43%; top: 63%; width: 32%; transform: rotate(24deg); }

.territory-lists {
  display: grid;
  gap: 16px;
}

.territory-lists article,
.capability-card,
.pricing-card,
.guide-panel,
.faq-item {
  border: 1px solid var(--tp-border);
  border-radius: 8px;
  background: #fff;
}

.territory-lists article {
  padding: 24px;
}

.territory-lists h3 {
  margin: 0 0 14px;
  color: var(--tp-navy);
  font-size: 1.08rem;
}

.territory-lists ul,
.guide-panel ol {
  margin: 0;
  padding-left: 20px;
}

.territory-lists li {
  margin: 6px 0;
  color: var(--tp-muted);
}

.capability-grid {
  display: grid;
  grid-template-columns: repeat(4, minmax(0, 1fr));
  gap: 16px;
}

.capability-card {
  padding: 22px;
}

.capability-card .material-symbols-outlined {
  color: var(--tp-green-dark);
  font-size: 2rem;
}

.capability-card h3,
.pricing-card h3,
.guide-panel h3 {
  margin: 10px 0 8px;
  color: var(--tp-navy);
}

.capability-card p,
.pricing-card p,
.guide-panel p,
.faq-item p {
  color: var(--tp-muted);
}

.pricing-section {
  width: 100%;
  max-width: none;
  background: linear-gradient(180deg, var(--tp-surface-alt), #fff);
}

.pricing-section > * {
  width: min(1180px, calc(100% - 36px));
  margin-left: auto;
  margin-right: auto;
}

.pricing-grid {
  display: grid;
  grid-template-columns: repeat(3, minmax(0, 1fr));
  gap: 18px;
}

.pricing-card {
  position: relative;
  display: flex;
  flex-direction: column;
  min-height: 100%;
  padding: 26px;
  box-shadow: 0 12px 28px rgba(11, 31, 51, 0.07);
}

.pricing-card.featured {
  border-color: rgba(24, 169, 87, 0.75);
  box-shadow: 0 18px 42px rgba(24, 169, 87, 0.17);
}

.best-value {
  align-self: flex-start;
  margin-bottom: 12px;
  padding: 5px 9px;
  border-radius: 8px;
  background: var(--tp-green-soft);
  color: var(--tp-green-dark);
  font-size: 0.78rem;
  font-weight: 800;
}

.price {
  margin: 10px 0;
  color: var(--tp-navy);
  font-size: 2.6rem;
  font-weight: 800;
  line-height: 1;
}

.price small {
  color: var(--tp-muted);
  font-size: 0.9rem;
  font-weight: 650;
}

.pricing-card ul {
  margin: 18px 0 24px;
  padding: 0;
  list-style: none;
}

.pricing-card li {
  display: flex;
  gap: 8px;
  margin: 9px 0;
  color: var(--tp-muted);
}

.pricing-card li::before {
  content: "check";
  color: var(--tp-green-dark);
  font-family: 'Material Symbols Outlined';
}

.pricing-card md-filled-button,
.pricing-card md-outlined-button {
  margin-top: auto;
}

.pricing-note {
  color: var(--tp-muted);
  text-align: center;
}

.guide-tabs {
  display: flex;
  flex-wrap: wrap;
  gap: 10px;
  margin-bottom: 18px;
}

.guide-tab {
  border: 1px solid var(--tp-border);
  border-radius: 8px;
  padding: 10px 12px;
  color: var(--tp-muted);
  background: #fff;
  cursor: pointer;
  font-weight: 700;
}

.guide-tab[aria-selected="true"] {
  border-color: var(--tp-green);
  color: var(--tp-green-dark);
  background: var(--tp-green-soft);
}

.guide-panel {
  padding: 28px;
}

.operational-section {
  display: grid;
  grid-template-columns: minmax(0, 0.9fr) minmax(340px, 0.7fr);
  gap: 32px;
  align-items: center;
  padding: 54px;
  border-radius: 8px;
  color: #fff;
  background: linear-gradient(135deg, var(--tp-navy), var(--tp-navy-2));
}

.operational-copy h2,
.operational-copy p {
  color: #fff;
}

.operational-copy p {
  opacity: 0.78;
}

.ops-list {
  display: grid;
  gap: 12px;
}

.ops-list > span {
  display: flex;
  align-items: center;
  gap: 12px;
  padding: 14px;
  border: 1px solid rgba(255, 255, 255, 0.16);
  border-radius: 8px;
  background: rgba(255, 255, 255, 0.06);
}

.ops-list .material-symbols-outlined {
  color: var(--tp-yellow);
}

.faq-list {
  display: grid;
  gap: 12px;
}

.faq-item {
  overflow: hidden;
}

.faq-item summary {
  cursor: pointer;
  padding: 18px 20px;
  color: var(--tp-navy);
  font-weight: 800;
}

.faq-item p {
  margin: 0;
  padding: 0 20px 20px;
}

.site-footer {
  display: flex;
  justify-content: space-between;
  gap: 18px;
  padding: 28px clamp(18px, 4vw, 56px);
  color: rgba(255, 255, 255, 0.72);
  background: var(--tp-navy);
  font-size: 0.92rem;
}

.site-footer a {
  color: #fff;
  font-weight: 700;
}

.checkout-form {
  display: grid;
  gap: 14px;
  min-width: min(560px, calc(100vw - 48px));
}

.field-label {
  display: grid;
  gap: 6px;
  color: var(--tp-muted);
  font-size: 0.86rem;
  font-weight: 700;
}

.notice {
  padding: 12px;
  border: 1px solid rgba(242, 186, 54, 0.45);
  border-radius: 8px;
  color: #785500;
  background: #fff7df;
}

.hidden {
  display: none !important;
}

.checkout-status {
  min-height: 24px;
  margin: 0;
  color: var(--tp-muted);
  font-weight: 700;
}

@media (max-width: 980px) {
  .site-header {
    grid-template-columns: 1fr;
    gap: 12px;
  }

  .site-nav {
    order: 3;
    justify-content: flex-start;
    overflow-x: auto;
    padding-bottom: 2px;
  }

  .header-actions {
    justify-content: space-between;
  }

  .hero,
  .coverage-grid,
  .operational-section {
    grid-template-columns: 1fr;
  }

  .hero {
    min-height: auto;
  }

  .hero-visual {
    min-height: 360px;
  }

  .capability-grid,
  .pricing-grid {
    grid-template-columns: repeat(2, minmax(0, 1fr));
  }
}

@media (max-width: 680px) {
  .compact-buy {
    display: none;
  }

  .section-shell {
    width: min(100% - 28px, 1180px);
    padding: 58px 0;
  }

  .hero h1 {
    font-size: 2.45rem;
  }

  .proof-strip,
  .capability-grid,
  .pricing-grid {
    grid-template-columns: 1fr;
  }

  .coverage-map,
  .map-panel {
    min-height: 310px;
  }

  .operational-section {
    width: min(100% - 28px, 1180px);
    padding: 30px 20px;
  }

  .site-footer {
    flex-direction: column;
  }
}

(function () {
  const state = {
    catalog: null,
    settings: null,
    paypal: null,
    lang: localStorage.getItem('tp_lang') || 'en',
    selectedPlan: null,
    selectedGuide: 0,
    paypalScriptLoaded: false,
  };

  const i18n = window.TruePointI18n || { en: {}, localized: {}, countryNames: {} };
  const $ = (selector, root = document) => root.querySelector(selector);
  const $$ = (selector, root = document) => Array.from(root.querySelectorAll(selector));

  function t(key) {
    return (i18n.localized[state.lang] && i18n.localized[state.lang][key])
      || i18n.en[key]
      || key;
  }

  function countryName(country) {
    const localized = i18n.countryNames[state.lang] || {};
    return localized[country.code] || country.name;
  }

  function formatPrice(value) {
    return new Intl.NumberFormat(state.lang === 'en' ? 'en' : state.lang, {
      style: 'currency',
      currency: state.paypal?.currency || 'EUR',
      maximumFractionDigits: 0,
    }).format(value);
  }

  async function init() {
    try {
      const response = await fetch('/api/catalog.php', { headers: { Accept: 'application/json' } });
      const data = await response.json();
      if (!data.ok) throw new Error(data.error || 'Catalog failed');
      state.catalog = data.content;
      state.settings = data.settings;
      state.paypal = data.paypal;
    } catch (error) {
      console.error(error);
      state.catalog = fallbackCatalog();
      state.settings = {};
      state.paypal = { configured: false, currency: 'EUR', clientId: '' };
    }

    setupLanguageSelect();
    applyTranslations();
    renderCountries();
    renderCapabilities();
    renderPricing();
    renderGuides();
    renderFaqs();
    bindCheckout();
  }

  function setupLanguageSelect() {
    const select = $('#languageSelect');
    select.innerHTML = '';
    const languages = state.catalog.languages || [{ code: 'en', native: 'English' }];
    for (const language of languages) {
      const option = document.createElement('option');
      option.value = language.code;
      option.textContent = language.native || language.label || language.code.toUpperCase();
      select.append(option);
    }
    if (!languages.some((language) => language.code === state.lang)) {
      state.lang = 'en';
    }
    select.value = state.lang;
    select.addEventListener('change', () => {
      state.lang = select.value;
      localStorage.setItem('tp_lang', state.lang);
      document.documentElement.lang = state.lang;
      applyTranslations();
      renderCountries();
      renderCapabilities();
      renderPricing();
      renderGuides();
      renderFaqs();
      updateCheckoutLabels();
    });
  }

  function applyTranslations() {
    document.documentElement.lang = state.lang;
    $$('[data-i18n]').forEach((node) => {
      const value = t(node.dataset.i18n);
      if (Array.isArray(value)) return;
      node.textContent = value;
    });
    updateCheckoutLabels();
  }

  function renderCountries() {
    const exclusive = $('#exclusiveCountries');
    const online = $('#onlineCountries');
    exclusive.innerHTML = '';
    online.innerHTML = '';
    for (const country of state.catalog.countries || []) {
      const item = document.createElement('li');
      item.textContent = countryName(country);
      (country.rights === 'online' ? online : exclusive).append(item);
    }
  }

  function renderCapabilities() {
    const grid = $('#capabilityGrid');
    grid.innerHTML = '';
    for (const item of state.catalog.capabilities || []) {
      const card = document.createElement('article');
      card.className = 'capability-card';
      card.innerHTML = `
        <span class="material-symbols-outlined" aria-hidden="true">${item.icon}</span>
        <h3>${escapeHtml(t(item.title_key))}</h3>
        <p>${escapeHtml(t(item.body_key))}</p>
      `;
      grid.append(card);
    }
  }

  function renderPricing() {
    const grid = $('#pricingGrid');
    grid.innerHTML = '';
    for (const plan of state.catalog.plans || []) {
      const card = document.createElement('article');
      card.className = `pricing-card${plan.featured ? ' featured' : ''}`;
      const buttonTag = plan.featured ? 'md-filled-button' : 'md-outlined-button';
      card.innerHTML = `
        ${plan.featured ? `<span class="best-value">${escapeHtml(t('pricing.best'))}</span>` : ''}
        <h3>${escapeHtml(t(plan.name_key))}</h3>
        <p>${escapeHtml(t(plan.persona_key))}</p>
        <div class="price">${formatPrice(plan.price)} <small>${escapeHtml(t('pricing.beforeTax'))}</small></div>
        <ul>
          <li>${escapeHtml(t('pricing.feature.1'))}</li>
          <li>${escapeHtml(t('pricing.feature.2'))}</li>
          <li>${escapeHtml(t('pricing.feature.3'))}</li>
          <li>${escapeHtml(t('pricing.feature.4'))}</li>
        </ul>
        <${buttonTag} data-plan-trigger="${plan.id}">${escapeHtml(t('pricing.choose'))}</${buttonTag}>
      `;
      grid.append(card);
    }
    $$('#pricingGrid [data-plan-trigger]').forEach((button) => {
      button.addEventListener('click', () => openCheckout(button.dataset.planTrigger));
    });
  }

  function renderGuides() {
    const tabs = $('#guideTabs');
    const panel = $('#guidePanel');
    const guides = state.catalog.receiver_guides || [];
    tabs.innerHTML = '';
    guides.forEach((guide, index) => {
      const button = document.createElement('button');
      button.className = 'guide-tab';
      button.type = 'button';
      button.role = 'tab';
      button.textContent = guide.brand;
      button.setAttribute('aria-selected', index === state.selectedGuide ? 'true' : 'false');
      button.addEventListener('click', () => {
        state.selectedGuide = index;
        renderGuides();
      });
      tabs.append(button);
    });

    const guide = guides[state.selectedGuide] || guides[0];
    if (!guide) return;
    const steps = t(guide.steps_key);
    panel.innerHTML = `
      <h3>${escapeHtml(guide.brand)}</h3>
      <ol>${(Array.isArray(steps) ? steps : []).map((step) => `<li>${escapeHtml(step)}</li>`).join('')}</ol>
    `;
  }

  function renderFaqs() {
    const list = $('#faqList');
    list.innerHTML = '';
    for (const faq of state.catalog.faqs || []) {
      const details = document.createElement('details');
      details.className = 'faq-item';
      details.innerHTML = `<summary>${escapeHtml(t(faq.q_key))}</summary><p>${escapeHtml(t(faq.a_key))}</p>`;
      list.append(details);
    }
  }

  function bindCheckout() {
    $('#closeCheckout').addEventListener('click', () => $('#checkoutDialog').close());
    $$('[data-plan-trigger]').forEach((button) => {
      button.addEventListener('click', () => openCheckout(button.dataset.planTrigger));
    });
  }

  function updateCheckoutLabels() {
    const labels = [
      ['#customerName', 'checkout.name'],
      ['#customerEmail', 'checkout.email'],
      ['#customerReceiver', 'checkout.receiver'],
      ['#customerNotes', 'checkout.notes'],
    ];
    for (const [selector, key] of labels) {
      const field = $(selector);
      if (field) field.setAttribute('label', t(key));
    }
  }

  function openCheckout(planId) {
    const plan = (state.catalog.plans || []).find((item) => item.id === planId) || state.catalog.plans?.[0];
    if (!plan) return;
    state.selectedPlan = plan;

    $('#selectedPlanSummary').textContent = `${t(plan.name_key)} - ${formatPrice(plan.price)} ${t('pricing.beforeTax')}`;
    renderCountrySelect();
    $('#checkoutStatus').textContent = '';
    $('#paypalButtons').innerHTML = '';

    const notice = $('#paypalSetupNotice');
    if (!state.paypal?.configured) {
      notice.textContent = t('checkout.configure');
      notice.classList.remove('hidden');
    } else {
      notice.classList.add('hidden');
      renderPayPalButtons();
    }

    $('#checkoutDialog').show();
  }

  function renderCountrySelect() {
    const select = $('#customerCountry');
    const prior = select.value;
    select.innerHTML = '';
    for (const country of state.catalog.countries || []) {
      const option = document.createElement('option');
      option.value = country.code;
      option.textContent = countryName(country);
      select.append(option);
    }
    if (prior) select.value = prior;
  }

  async function renderPayPalButtons() {
    await loadPayPalScript();
    if (!window.paypal) {
      $('#checkoutStatus').textContent = t('checkout.error');
      return;
    }

    window.paypal.Buttons({
      style: { layout: 'vertical', color: 'gold', shape: 'rect', label: 'paypal' },
      createOrder: async () => {
        const payload = checkoutPayload();
        if (!payload) throw new Error('Missing customer fields');
        $('#checkoutStatus').textContent = t('checkout.creating');
        const response = await fetch('/api/create-order.php', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json', Accept: 'application/json' },
          body: JSON.stringify(payload),
        });
        const data = await response.json();
        if (!data.ok) throw new Error(data.error || 'PayPal order failed');
        state.pendingLocalOrder = data.local_id;
        return data.paypal_order_id;
      },
      onApprove: async (data) => {
        $('#checkoutStatus').textContent = t('checkout.capturing');
        const response = await fetch('/api/capture-order.php', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json', Accept: 'application/json' },
          body: JSON.stringify({ paypal_order_id: data.orderID, local_id: state.pendingLocalOrder }),
        });
        const result = await response.json();
        if (!result.ok) throw new Error(result.error || 'Payment capture failed');
        showSuccess(result.order);
      },
      onError: (error) => {
        console.error(error);
        $('#checkoutStatus').textContent = t('checkout.error');
      },
    }).render('#paypalButtons');
  }

  function checkoutPayload() {
    const payload = {
      plan_id: state.selectedPlan.id,
      customer: {
        name: $('#customerName').value.trim(),
        email: $('#customerEmail').value.trim(),
        country: $('#customerCountry').value,
        receiver: $('#customerReceiver').value.trim(),
        notes: $('#customerNotes').value.trim(),
      },
    };

    if (!payload.customer.name || !payload.customer.email || !payload.customer.country) {
      $('#checkoutStatus').textContent = t('checkout.required');
      return null;
    }

    return payload;
  }

  function showSuccess(order) {
    const provisioning = order.provisioning || {};
    $('#checkoutStatus').innerHTML = `
      <strong>${escapeHtml(t('checkout.success'))}</strong><br>
      NTRIP: ${escapeHtml(provisioning.ntrip_host || '')}:${escapeHtml(String(provisioning.ntrip_port || ''))}<br>
      Mountpoint: ${escapeHtml(provisioning.mountpoint || '')}<br>
      Username: ${escapeHtml(provisioning.username || '')}
    `;
  }

  function loadPayPalScript() {
    if (state.paypalScriptLoaded) return Promise.resolve();
    return new Promise((resolve, reject) => {
      const script = document.createElement('script');
      const params = new URLSearchParams({
        'client-id': state.paypal.clientId,
        currency: state.paypal.currency || 'EUR',
        intent: 'capture',
      });
      script.src = `https://www.paypal.com/sdk/js?${params.toString()}`;
      script.onload = () => {
        state.paypalScriptLoaded = true;
        resolve();
      };
      script.onerror = reject;
      document.head.append(script);
    });
  }

  function escapeHtml(value) {
    return String(value)
      .replaceAll('&', '&amp;')
      .replaceAll('<', '&lt;')
      .replaceAll('>', '&gt;')
      .replaceAll('"', '&quot;')
      .replaceAll("'", '&#039;');
  }

  function fallbackCatalog() {
    return {
      languages: [{ code: 'en', native: 'English' }],
      plans: [
        { id: 'monthly', name_key: 'plan.monthly.name', persona_key: 'plan.monthly.persona', price: 50 },
        { id: 'quarterly', name_key: 'plan.quarterly.name', persona_key: 'plan.quarterly.persona', price: 120 },
        { id: 'annual', name_key: 'plan.annual.name', persona_key: 'plan.annual.persona', price: 380, featured: true },
      ],
      countries: [],
      capabilities: [],
      receiver_guides: [],
      faqs: [],
    };
  }

  document.addEventListener('DOMContentLoaded', init);
})();
